                parent.display(),
                e
            ));
        }
    }
    if let Err(e) = std::fs::copy(&assay, &canonical) {
        return rbtdre_Verdict::Fail(format!(
            "copy assay RBRA → governor canonical {}: {}",
            canonical.display(),
            e
        ));
    }
    rbtdre_Verdict::Pass
